import React from "react";

const SocialShare = [
  {
    iconName: "fa fa-instagram",
    link: "https://www.instagram.com/hemubisht13/",
  },
  {
    iconName: "fa fa-linkedin",
    link: "https://linkedin.com/in/hari-singh-bisht-02bb101a1",
  },
  { iconName: "fa fa-github", link: "https://github.com/hemuu12" },
];

const Social = () => {
  return (
    <>
    <h1>Social Links</h1>
    <ul className="social list-unstyled pt-1 mb-5" style={{display:"flex",gap:"50px",width:"500px"}}>
      {SocialShare.map((val, i) => (
        <li key={i}>
          <a  href={val.link} target="_blank" rel="noreferrer">
            <i  className={val.iconName}></i>
          </a>
        </li>
      ))}
    </ul>
    </>
  );
};

export default Social;
