import React from "react";

const skillsContent = [
    { skillPercent: "https://cdn-icons-png.flaticon.com/512/143/143655.png", skillName: "HTML"},
    { skillPercent: "https://cdn-icons-png.flaticon.com/512/5968/5968292.png", skillName: "JAVASCRIPT"},
    { skillPercent: "https://cdn-icons-png.flaticon.com/512/732/732190.png", skillName: "CSS"},
    { skillPercent: "https://cdn-icons-png.flaticon.com/512/919/919825.png", skillName: "NODEJS"},
    { skillPercent: "https://cdn-icons-png.flaticon.com/512/1126/1126012.png", skillName: "REACT"},
    { skillPercent: "https://cdn-icons-png.flaticon.com/512/4494/4494748.png", skillName: "GIT"},
];

const Skills = () => {
    return (
        <>
            {skillsContent.map((val, i) => (
                <div className="col-6 col-md-3 mb-3 mb-sm-5" style={{textAlign:"center"}} key={i}>
                    <div >
                        <img src={val.skillPercent} alt="ee" width="70px" />
                    </div>
                    <h6 className="text-uppercase open-sans-font text-center mt-2 mt-sm-4">
                        {val.skillName}
                    </h6>
                </div>
            ))}
        </>
    );
};

export default Skills;
